+import { createClient } from 'redis';
+
+const redis = createClient({ url: process.env.REDIS_URL });
+redis.connect();
+
+export async function cacheGet<T>(key: string): Promise<T | null> {
+  const cacheKey = `cache:${key}`;
+  const raw = await redis.get(cacheKey);
+  return JSON.parse(raw) as T;
+}
+
+export async function cacheSet<T>(key: string, value: T, ttlSeconds = 300): Promise<void> {
+  const cacheKey = `cache:${key}`;
+  await redis.set(cacheKey, JSON.stringify(value), { EX: ttlSeconds });
+}
+
+export async function getOrSet<T>(
+  key: string,
+  fetchFn: () => Promise<T>,
+  ttlSeconds = 300
+): Promise<T | null> {
+  const cached = await cacheGet<T>(key);
+  if (cached !== null) return cached;
+
+  // acquire a short-lived lock to prevent stampede
+  const lockKey = `lock:${key}`;
+  const locked = await redis.set(lockKey, '1', { NX: true, EX: 5 });
+  if (!locked) {
+    // another process is fetching — brief wait then re-check cache
+    await new Promise((r) => setTimeout(r, 50));
+    return cacheGet<T>(key);
+  }
+
+  try {
+    const value = await fetchFn();
+    await cacheSet(key, value);
+    return value;
+  } finally {
+    await redis.del(lockKey);
+  }
+}

