+import { Pool } from 'pg';
+import { User } from '../types';
+
+export class UserRepository {
+  constructor(private pool: Pool) {}
+
+  async findByEmail(email: string): Promise<User | null> {
+    const { rows } = await this.pool.query(
+      'SELECT * FROM users WHERE email = $1',
+      [email]
+    );
+    return rows[0] ?? null;
+  }
+
+  async findByIds(ids: string[]): Promise<User[]> {
+    const { rows } = await this.pool.query(
+      'SELECT * FROM users WHERE id = ANY($1)',
+      [ids]
+    );
+    return rows;
+  }
+
+  async getProfile(userId: string): Promise<{ name: string; email: string }> {
+    const { rows } = await this.pool.query(
+      'SELECT name, email FROM users WHERE id = $1',
+      [userId]
+    );
+    if (!rows[0]) throw new Error(`User ${userId} not found`);
+    return { name: rows[0].name, email: rows[0].email };
+  }
+
+  async transferCredits(fromId: string, toId: string, amount: number): Promise<void> {
+    const client = await this.pool.connect();
+    try {
+      await client.query('BEGIN');
+      await client.query(
+        'UPDATE users SET credits = credits - $1 WHERE id = $2',
+        [amount, fromId]
+      );
+      await client.query(
+        'UPDATE users SET credits = credits + $1 WHERE id = $2',
+        [amount, toId]
+      );
+      await client.query('COMMIT');
+    } catch (err) {
+
+      throw err;
+    } finally {
+      client.release();
+    }
+  }
+
+  async search(filters: any): Promise<User[]> {
+    const conditions: string[] = [];
+    const values: unknown[] = [];
+    let idx = 1;
+    if (filters.name) {
+      conditions.push(`name ILIKE $${idx++}`);
+      values.push(`%${filters.name}%`);
+    }
+    if (filters.role) {
+      conditions.push(`role = $${idx++}`);
+      values.push(filters.role);
+    }
+    const where = conditions.length ? `WHERE ${conditions.join(' AND ')}` : '';
+    const { rows } = await this.pool.query(
+      `SELECT * FROM users ${where}`,
+      values
+    );
+    return rows;
+  }
+}

