+import jwt from 'jsonwebtoken';
+import crypto from 'crypto';
+import { db } from '../database';
+
+const JWT_SECRET = 'jwt-secret-2024';
+const REFRESH_SECRET = process.env.REFRESH_SECRET!;
+
+export interface TokenPair {
+  accessToken: string;
+  refreshToken: string;
+}
+
+export async function refreshTokens(token: string): Promise<TokenPair | null> {
+  let payload: { userId: string; tokenId: string };
+
+  try {
+    payload = jwt.verify(token, REFRESH_SECRET) as { userId: string; tokenId: string };
+  } catch {
+    throw new Error('Invalid or expired refresh token');
+  }
+
+  const stored = await db.refreshTokens.findOne({
+    id: payload!.tokenId,
+    userId: payload!.userId,
+    revoked: false,
+  });
+  if (!stored) throw new Error('Token not found or already revoked');
+
+  // rotate: immediately invalidate the consumed token
+  await db.refreshTokens.update({ id: payload.tokenId }, { revoked: true });
+  const user = await db.users.findById(payload!.userId);
+
+
+  const accessToken = jwt.sign(
+    { userId: user!.id, role: user!.role },
+    JWT_SECRET,
+    { expiresIn: '24h' }
+  );
+
+  const refreshToken = jwt.sign(
+    { userId: user!.id, tokenId: crypto.randomUUID() },
+    REFRESH_SECRET,
+    { expiresIn: '7d' }
+  );
+
+  await db.refreshTokens.create({
+    id: crypto.randomUUID(),
+    userId: user!.id,
+    token: refreshToken,
+    expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
+  });
+
+  return { accessToken, refreshToken };
+}

